const svg=$('#tl-svg'), out=$('#tl-out');
const btnShow=$('#tl-show'), btnT=$('#tl-T'), btnS=$('#tl-S'), btnDeep=$('#tl-deeper'), btnR=$('#tl-reset');
const W=680,H=380,padL=40,padR=40,padT=20,padB=40;
const xMin=-2.5,xMax=2.5,yMin=0,yMax=3;
const plotH=H-padT-padB, plotW=W-padL-padR;
function X(xx){return padL+(xx-xMin)/(xMax-xMin)*plotW;}
function Y(yy){return padT+plotH-(yy-yMin)/(yMax-yMin)*plotH;}

// tiles as arrays of matrices applied to F: each is a "word" [{op:'T',k} or {op:'S'}]
// We just store the 2x2 matrices.
function mul(A,B){
  return [
    [A[0][0]*B[0][0]+A[0][1]*B[1][0], A[0][0]*B[0][1]+A[0][1]*B[1][1]],
    [A[1][0]*B[0][0]+A[1][1]*B[1][0], A[1][0]*B[0][1]+A[1][1]*B[1][1]],
  ];
}
function applyM(M, z){
  const a=M[0][0], b=M[0][1], c=M[1][0], d=M[1][1];
  const nr=a*z.x+b, ni=a*z.y;
  const dr=c*z.x+d, di=c*z.y;
  const den=dr*dr+di*di;
  return {x:(nr*dr+ni*di)/den, y:(ni*dr-nr*di)/den};
}
const I = [[1,0],[0,1]];
const T = [[1,1],[0,1]];
const Ti = [[1,-1],[0,1]];
const Sm = [[0,-1],[1,0]];

let tiles = [I];

function boundaryOfF(){
  // F boundary as list of z's: vertical line at x=-1/2 from y=sqrt(3)/2 up to yMax, then top line x in [-1/2,1/2] at yMax,
  // then vertical at x=1/2 down to sqrt(3)/2, then arc of unit circle from (1/2, sqrt(3)/2) to (-1/2, sqrt(3)/2).
  const pts=[];
  const y0 = Math.sqrt(3)/2;
  // left wall: (-0.5, y0) -> (-0.5, yMax)
  pts.push({x:-0.5, y:y0});
  for(let y=y0; y<=yMax; y+=0.05) pts.push({x:-0.5, y});
  // top: left to right at yMax
  for(let x=-0.5; x<=0.5; x+=0.05) pts.push({x, y:yMax});
  // right wall down
  for(let y=yMax; y>=y0; y-=0.05) pts.push({x:0.5, y});
  // arc from (0.5,y0) to (-0.5,y0) along unit circle upper half
  const N=40;
  for(let i=0;i<=N;i++){
    const th = Math.PI/3 + i*(Math.PI - 2*Math.PI/3)/N; // from pi/3 to 2pi/3
    pts.push({x:Math.cos(th), y:Math.sin(th)});
  }
  return pts;
}
const FPTS = boundaryOfF();

function draw(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  svg.appendChild(SVG('rect',{x:padL,y:padT,width:plotW,height:plotH,
    fill:'#0b0f16',stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:padL,x2:W-padR,y1:Y(0),y2:Y(0),stroke:'var(--pink)','stroke-width':2}));
  // unit circle (reference)
  const N=100;
  let du='';
  for(let i=0;i<=N;i++){
    const th=Math.PI*i/N;
    const xx=Math.cos(th), yy=Math.sin(th);
    du += (i===0?'M ':' L ') + X(xx) + ' ' + Y(yy);
  }
  svg.appendChild(SVG('path',{d:du, fill:'none', stroke:'var(--line)','stroke-dasharray':'3 4','stroke-width':1}));

  // draw each tile
  for(let k=0;k<tiles.length;k++){
    const M = tiles[k];
    let d='';
    let start=true;
    for(const z of FPTS){
      const w = applyM(M, z);
      if(w.y <= 0 || w.y > yMax*1.02) { start=true; continue; }
      d += (start ? 'M ':' L ') + X(w.x) + ' ' + Y(w.y);
      start=false;
    }
    const isId = M[0][0]===1 && M[0][1]===0 && M[1][0]===0 && M[1][1]===1;
    svg.appendChild(SVG('path',{d, fill: isId?'rgba(255,216,102,0.18)':'rgba(88,196,221,0.10)',
      stroke: isId?'var(--yellow)':'var(--cyan)', 'stroke-width': isId?2:1.3}));
  }

  out.textContent = `tiles rendered: ${tiles.length}\n`+
    `F (yellow): |Re z| ≤ 1/2, |z| ≥ 1  — fundamental domain for SL₂(ℤ).\n`+
    `generators: T (z↦z+1) shifts horizontally; S (z↦−1/z) inverts through unit circle.`;
}

btnShow.addEventListener('click',()=>{ tiles=[I]; draw(); });
btnT.addEventListener('click',()=>{
  const seen = new Set(tiles.map(m=>JSON.stringify(m)));
  const add = [mul(T,I), mul(Ti,I), mul(mul(T,T),I), mul(mul(Ti,Ti),I)];
  for(const m of add) if(!seen.has(JSON.stringify(m))) tiles.push(m);
  draw();
});
btnS.addEventListener('click',()=>{
  const base = [...tiles];
  const seen = new Set(tiles.map(m=>JSON.stringify(m)));
  for(const m of base){
    const nm = mul(Sm, m);
    if(!seen.has(JSON.stringify(nm))) { tiles.push(nm); seen.add(JSON.stringify(nm)); }
  }
  draw();
});
btnDeep.addEventListener('click',()=>{
  // add a few more: TS, STS, ST, TST, etc.
  const base=[...tiles];
  const seen = new Set(tiles.map(m=>JSON.stringify(m)));
  const gens=[T,Ti,Sm];
  for(const m of base){
    for(const g of gens){
      const nm = mul(g, m);
      if(!seen.has(JSON.stringify(nm))){ tiles.push(nm); seen.add(JSON.stringify(nm)); }
    }
  }
  draw();
});
btnR.addEventListener('click',()=>{ tiles=[I]; draw(); });
draw();

